import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Button, Modal, Form, Badge } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';
import { courseService } from '../services/courseService';
import { Course } from '../types';
import Loading from '../components/Loading';
import ErrorMessage from '../components/ErrorMessage';

const Dashboard: React.FC = () => {
  const { user } = useAuth();
  const [myCourses, setMyCourses] = useState<Course[]>([]);
  const [allCourses, setAllCourses] = useState<Course[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showJoinModal, setShowJoinModal] = useState(false);
  const [courseName, setCourseName] = useState('');
  const [courseCode, setCourseCode] = useState('');
  const [courseDescription, setCourseDescription] = useState('');
  const [joinCode, setJoinCode] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [myCoursesData, allCoursesData] = await Promise.all([
        courseService.getMyCourses(),
        courseService.getAll()
      ]);
      setMyCourses(myCoursesData);
      setAllCourses(allCoursesData);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load courses');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await courseService.create(courseName, courseCode, courseDescription);
      setShowCreateModal(false);
      setCourseName('');
      setCourseCode('');
      setCourseDescription('');
      fetchData();
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to create course');
    }
  };

  const handleJoinCourse = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const course = allCourses.find(c => c.code === joinCode);
      if (!course) {
        setError('Course not found with this code');
        return;
      }
      await courseService.join(course.id);
      setShowJoinModal(false);
      setJoinCode('');
      fetchData();
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to join course');
    }
  };

  if (loading) {
    return <Loading />;
  }

  return (
    <Container className="py-4">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h1>Welcome, {user?.username}!</h1>
          <p className="text-muted">Manage your courses and study resources</p>
        </div>
        <div>
          <Button variant="primary" className="me-2" onClick={() => setShowCreateModal(true)}>
            Create Course
          </Button>
          <Button variant="outline-primary" onClick={() => setShowJoinModal(true)}>
            Join Course
          </Button>
        </div>
      </div>

      <ErrorMessage message={error} onClose={() => setError('')} />

      <Row className="mb-4">
        <Col>
          <h3>
            My Courses <Badge bg="primary">{myCourses.length}</Badge>
          </h3>
        </Col>
      </Row>

      {myCourses.length === 0 ? (
        <Card className="text-center p-4 mb-4">
          <Card.Body>
            <Card.Title>You're not enrolled in any courses yet</Card.Title>
            <Card.Text>Create a new course or join an existing one to get started.</Card.Text>
          </Card.Body>
        </Card>
      ) : (
        <Row className="mb-4">
          {myCourses.map((course) => (
            <Col key={course.id} md={4} className="mb-3">
              <Card>
                <Card.Body>
                  <Card.Title>{course.name}</Card.Title>
                  <Card.Subtitle className="mb-2 text-muted">{course.code}</Card.Subtitle>
                  <Card.Text>{course.description}</Card.Text>
                  <div className="d-flex justify-content-between align-items-center">
                    <small className="text-muted">
                      {course.member_count} member{course.member_count !== 1 ? 's' : ''}
                    </small>
                    <a href={`/courses/${course.id}`} className="btn btn-sm btn-primary">
                      View Course
                    </a>
                  </div>
                </Card.Body>
              </Card>
            </Col>
          ))}
        </Row>
      )}

      <Row>
        <Col>
          <h3>All Available Courses</h3>
        </Col>
      </Row>

      {allCourses.length === 0 ? (
        <Card className="text-center p-4">
          <Card.Body>
            <Card.Title>No courses available</Card.Title>
            <Card.Text>Create the first course to get started!</Card.Text>
          </Card.Body>
        </Card>
      ) : (
        <Row>
          {allCourses.map((course) => {
            const isEnrolled = myCourses.some(c => c.id === course.id);
            return (
              <Col key={course.id} md={4} className="mb-3">
                <Card>
                  <Card.Body>
                    <Card.Title>{course.name}</Card.Title>
                    <Card.Subtitle className="mb-2 text-muted">{course.code}</Card.Subtitle>
                    <Card.Text>{course.description}</Card.Text>
                    <div className="d-flex justify-content-between align-items-center">
                      <small className="text-muted">
                        By {course.creator_name} • {course.member_count} members
                      </small>
                      {isEnrolled ? (
                        <Badge bg="success">Enrolled</Badge>
                      ) : (
                        <a
                          href="#"
                          className="btn btn-sm btn-outline-primary"
                          onClick={async (e) => {
                            e.preventDefault();
                            try {
                              await courseService.join(course.id);
                              fetchData();
                            } catch (err: any) {
                              setError(err.response?.data?.error || 'Failed to join course');
                            }
                          }}
                        >
                          Join
                        </a>
                      )}
                    </div>
                  </Card.Body>
                </Card>
              </Col>
            );
          })}
        </Row>
      )}

      {/* Create Course Modal */}
      <Modal show={showCreateModal} onHide={() => setShowCreateModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Create New Course</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleCreateCourse}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label>Course Name</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., Data Structures and Algorithms"
                value={courseName}
                onChange={(e) => setCourseName(e.target.value)}
                required
              />
            </Form.Group>
            <Form.Group className="mb-3">
              <Form.Label>Course Code</Form.Label>
              <Form.Control
                type="text"
                placeholder="e.g., CS201"
                value={courseCode}
                onChange={(e) => setCourseCode(e.target.value)}
                required
              />
            </Form.Group>
            <Form.Group className="mb-3">
              <Form.Label>Description</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                placeholder="Optional course description"
                value={courseDescription}
                onChange={(e) => setCourseDescription(e.target.value)}
              />
            </Form.Group>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setShowCreateModal(false)}>
              Cancel
            </Button>
            <Button variant="primary" type="submit">
              Create
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>

      {/* Join Course Modal */}
      <Modal show={showJoinModal} onHide={() => setShowJoinModal(false)}>
        <Modal.Header closeButton>
          <Modal.Title>Join a Course</Modal.Title>
        </Modal.Header>
        <Form onSubmit={handleJoinCourse}>
          <Modal.Body>
            <Form.Group className="mb-3">
              <Form.Label>Course Code</Form.Label>
              <Form.Control
                type="text"
                placeholder="Enter the course code"
                value={joinCode}
                onChange={(e) => setJoinCode(e.target.value)}
                required
              />
            </Form.Group>
            <p className="text-muted">
              Available courses: {allCourses.filter(c => !myCourses.some(mc => mc.id === c.id)).map(c => c.code).join(', ') || 'None'}
            </p>
          </Modal.Body>
          <Modal.Footer>
            <Button variant="secondary" onClick={() => setShowJoinModal(false)}>
              Cancel
            </Button>
            <Button variant="primary" type="submit">
              Join
            </Button>
          </Modal.Footer>
        </Form>
      </Modal>
    </Container>
  );
};

export default Dashboard;
